  it('should resolve a promise with parsed JSON', (done) => {
    const file = path.join(TEST_DIR, 'somefile.json')
    const obj = { name: 'JP' }
    fs.writeFileSync(file, JSON.stringify(obj))

    jf.readFile(file)
      .then((data) => {
