          done()
        }
        bothDone = true
      })

      jf.readFile(file, { throws: false }, (err, obj2) => {
        assert.ifError(err)
        assert.strictEqual(obj2, null)
        if (bothDone) {
          done()
        }
        bothDone = true
      })
    })

    it('should resolve the promise with null as data', (done) => {
      jf.readFile(file, { throws: false })
        .then(data => {
          assert.strictEqual(data, null)
          done()
