      assert.strictEqual(data.name, obj.name)
      done()
    })

    it('should have a the EOL symbol at the end of file when finalEOL is a truth value in options', (done) => {
      const file = path.join(TEST_DIR, 'somefile2.json')
      const obj = { name: 'jp' }
